sp_widget.client_script:
api.controller = function($scope, $timeout, $location) {
  var c = this;

	c.filters = {
  dateRange: "30",  // ✅ default
  table: "",
  type: ""
};
  c.refreshData = function() {
    c.server.update();
  };

  $timeout(function () {

    if (typeof Chart === "undefined") {
      console.error("Chart.js not loaded");
      return;
    }

    var ctx = document.getElementById('donutChart');
    if (!ctx) return;

    new Chart(ctx, {
      type: 'doughnut',
      data: {
        labels: ['Success', 'Failed', 'Partial'],
        datasets: [{
          data: [c.data.successCount, c.data.failedCount, c.data.partialCount],
          backgroundColor: [
            '#116AF8',
            '#ef4444',
            '#f59e0b'
          ],
          borderWidth: 0
        }]
      },
      options: {
        responsive: false,
        cutout: '70%',
        plugins: {
          legend: { display: false }
        }
      }
    });

  }, 500); // slight delay helps in Service Portal
	//click handler
	c.onLegendClick = function(type) {
  alert("Clicked: " + type);

  // 🔥 future:
  // filter chart
  // open records
  // navigate
};
//directing to page	
c.goToDetails = function(status) {

  var url = '?id=tracenow_migration_details&status=' + status;

  $location.url(url);
};	
};

sp_widget.css:
/* LAYOUT */
.layout {
  display: flex;
  max-height: calc(100vh - 64px);
  position: relative;
  background: linear-gradient(
    to bottom right,
    #ffffff 0%,
    rgba(17, 106, 248, 0.05) 50%,
    rgba(10, 80, 245, 0.10) 100%
  );
}

/* SIDEBAR */
.sidebar-area {
  flex-basis: 260px;
  flex-shrink: 0;
  height: 100%;
}

/* MAIN CONTENT */
.content-area {
  position: relative;
  display: flex;
  flex-direction: column;
  height: 100%;
  gap: 30px;
  margin: 0 auto;
  overflow-y: auto;
  height: calc(100vh - 64px);
  width: 100%;
  padding: 30px 15%;
}

.dash-wrap {
  padding: 20px;
  background: #f1f5f9;
}

/* Sidebar width */
.dm-sidebar-slot {
  flex-basis: 260px;
  flex-shrink: 0;
  height: 100%;
}

@media(max-width:1600px) {
  .content-area {
    padding: 30px;
  }
}

/* HERO CONTAINER */
.hero {
  position: relative;
  border-radius: 24px;
  padding: 48px;
  overflow: hidden;
  background: linear-gradient(135deg, #f8fafc, #dbeafe);
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.08);
}

/* subtle glow blobs */
.hero::before {
  content: "";
  position: absolute;
  top: -80px;
  right: -80px;
  width: 300px;
  height: 300px;
  background: radial-gradient(circle, rgba(17, 106, 248, 0.22), transparent 70%);
  filter: blur(60px);
}

.hero::after {
  content: "";
  position: absolute;
  bottom: -60px;
  left: -60px;
  width: 250px;
  height: 250px;
  background: radial-gradient(circle, rgba(155, 192, 252, 0.28), transparent 70%);
  filter: blur(60px);
}

/* INNER LAYOUT */
.hero-content {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  position: relative;
  z-index: 2;
}

.hero-left {
  max-width: 60%;
}

/* BADGE */
.mic-badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: rgba(17, 106, 248, 0.10);
  color: #116AF8;
  border-radius: 999px;
  padding: 6px 14px;
  font-size: 13px;
  font-weight: 500;
  margin-bottom: 18px;
}

.dot {
  width: 8px;
  height: 8px;
  background: #22c55e;
  border-radius: 50%;
}

/* HEADING */
.hero h1 {
  font-size: 42px;
  font-weight: 700;
  color: #0f172a;
  line-height: 1.2;
}

.hero h1 span {
  color: #116AF8;
}

/* DESCRIPTION */
.hero p {
  margin-top: 14px;
  color: #475569;
  font-size: 16px;
  line-height: 1.6;
}

/* LINK */
.overview-link {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  margin-top: 18px;
  font-size: 14px;
  color: #0A50F5;
  cursor: pointer;
  transition: 0.3s;
}

.overview-link:hover {
  color: #083EC4;
}

/* ACTIONS */
.hero-actions {
  display: flex;
  gap: 14px;
}

/* BUTTON BASE */
.btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  border-radius: 14px;
  padding: 12px 18px;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: 0.25s ease;
}

/* GHOST BUTTON */
.btn.ghost {
  background: rgba(255, 255, 255, 0.6);
  border: 1px solid rgba(0, 0, 0, 0.08);
  color: #0f172a;
  backdrop-filter: blur(6px);
}

.btn.ghost:hover {
  background: #ffffff;
  transform: translateY(-2px);
}

/* PRIMARY BUTTON */
.btn.primary {
  background: linear-gradient(135deg, #116AF8, #0A50F5);
  color: #fff;
  box-shadow: 0 10px 25px rgba(17, 106, 248, 0.35);
}

.btn.primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 14px 30px rgba(17, 106, 248, 0.45);
}

/* FILTER */
.filter-bar {
  margin-top: 20px;
  background: #e2e8f0;
  padding: 14px;
  border-radius: 16px;
  display: flex;
  align-items: center;
  gap: 16px;
}

.filter-item {
  display: flex;
  align-items: center;
  gap: 6px;
  background: #fff;
  padding: 8px 12px;
  border-radius: 10px;
}

.filter-item select {
  border: none;
  outline: none;
  background: transparent;
}

/* CARDS */
.cards {
  display: flex;
  gap: 20px;
  margin-top: 24px;
}

/* BASE CARD */
.card {
  flex: 1;
  position: relative;
  padding: 22px;
  border-radius: 18px;
  background: rgba(255, 255, 255, 0.75);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.08);
  transition: all 0.25s ease;
  overflow: hidden;
}

/* HOVER EFFECT */
.card:hover {
  transform: translateY(-6px) scale(1.01);
  box-shadow: 0 18px 40px rgba(0, 0, 0, 0.12);
}

/* TOP BAR GLOW */
.card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  height: 4px;
  width: 100%;
  border-radius: 18px 18px 0 0;
}

/* ICON */
.card .icon {
  width: 44px;
  height: 44px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 18px;
  margin-bottom: 10px;
}

/* HEADER */
.card-top {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

/* TREND */
.trend {
  font-size: 13px;
  font-weight: 600;
  color: #16a34a;
}

/* TEXT */
.card p {
  color: #64748b;
  font-size: 14px;
  margin-top: 6px;
}

.card h2 {
  font-size: 30px;
  font-weight: 700;
  margin: 6px 0;
  letter-spacing: -0.5px;
}

.sub {
  color: #94a3b8;
  font-size: 13px;
}

/* COLOR THEMES */

/* BLUE */
.card.blue::before {
  background: linear-gradient(90deg, #9BC0FC, #116AF8);
}
.card.blue .icon {
  background: rgba(155, 192, 252, 0.20);
  color: #116AF8;
}

/* GREEN */
.card.green::before {
  background: linear-gradient(90deg, #22c55e, #16a34a);
}
.card.green .icon {
  background: rgba(34, 197, 94, 0.15);
  color: #16a34a;
}

/* PURPLE */
.card.purple::before {
  background: linear-gradient(90deg, #8b5cf6, #7c3aed);
}
.card.purple .icon {
  background: rgba(139, 92, 246, 0.15);
  color: #7c3aed;
}

/* ORANGE */
.card.orange::before {
  background: linear-gradient(90deg, #fb923c, #f97316);
}
.card.orange .icon {
  background: rgba(249, 115, 22, 0.15);
  color: #ea580c;
}

/* VISUALIZATION */
.analytics-row {
  display: flex;
  gap: 20px;
  margin-top: 24px;
  align-items: stretch;
  flex-wrap: nowrap;
  width: 100%;
}

/* CARD BASE */
.analytics-card {
  background: #fff;
  border-radius: 18px;
  padding: 20px;
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.06);
}

.analytics-card.small {
  flex: 0 0 340px;
}

.analytics-card.large {
  flex: 1;
}

/* HEADER */
.card-header {
  display: flex;
  align-items: center;
  gap: 10px;
  font-weight: 600;
  color: #1e293b;
}

.sub-text {
  font-size: 13px;
  color: #64748b;
  margin-top: 4px;
}

/* GAUGE */
.gauge-wrap {
  position: relative;
  width: 100%;
  display: flex;
  justify-content: center;
  align-items: center;
  flex-direction: column;
}

/* SVG */
.gauge-svg {
  width: 240px;
  height: 140px;
}

/* arcs */
.gauge-bg {
  fill: none;
  stroke: #e2e8f0;
  stroke-width: 14;
  stroke-linecap: round;
}

.gauge-progress {
  fill: none;
  stroke: #116AF8;
  stroke-width: 14;
  stroke-linecap: round;
  transition: stroke-dashoffset 0.6s ease;
}

/* NEEDLE FIX */
.needle-wrap {
  position: absolute;
  left: 50%;
  top: 100px;
  transform: translate(-50%, -50%);
  width: 0;
  height: 0;
}

.needle-line {
  width: 2px;
  height: 75px;
  background: #1e293b;
  transform-origin: bottom center;
  position: absolute;
  bottom: 0;
  left: 50%;
  transform: translateX(-50%);
}

.needle-center {
  width: 12px;
  height: 12px;
  background: #1e293b;
  border-radius: 50%;
  position: absolute;
  bottom: -6px;
  left: 50%;
  transform: translateX(-50%);
}

/* TEXT */
.gauge-center {
  text-align: center;
  margin-top: -10px;
}

.small-btn {
  margin-top: 10px;
  padding: 6px 12px;
}

.btn a {
  color: #ffffff;
  text-decoration: none;
  display: flex;
  align-items: center;
  gap: 6px;
}

/* SMALL BUTTON BASE */
.small-btn {
  background: linear-gradient(90deg, #116AF8, #0A50F5);
  color: #fff;
  transition: all 0.25s ease;
}

/* HOVER EFFECT */
.small-btn:hover {
  background: linear-gradient(90deg, #0A50F5, #083EC4);
  transform: translateY(-1px);
  box-shadow: 0 6px 16px rgba(17, 106, 248, 0.32);
}

/* ARROW ANIMATION */
.small-btn i {
  transition: transform 0.2s ease;
}

/* MOVE ARROW SLIGHTLY */
.small-btn:hover i {
  transform: translateX(3px);
}

/* DONUT */
.donut-wrap {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 30px;
  margin-top: 20px;
}

.donut {
  width: 200px;
  height: 200px;
  border-radius: 50%;
  background: #116AF8;
  position: relative;
}

.donut::after {
  content: "";
  width: 120px;
  height: 120px;
  background: #fff;
  border-radius: 50%;
  position: absolute;
  top: 40px;
  left: 40px;
}

canvas#donutChart {
  max-width: 220px;
}

/* LEGEND */
.legend {
  margin-left: 10px;
  flex: 1;
}

.legend-item {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 16px;
  cursor: pointer;
  padding: 10px 12px;
  border-radius: 12px;
  transition: all 0.25s ease;
}

/* HOVER EFFECT */
.legend-item:hover {
  background: #116AF8;
  transform: translateX(6px);
  box-shadow: 0 6px 16px rgba(0, 0, 0, 0.06);
}

/* ACTIVE CLICK FEEL */
.legend-item:active {
  transform: scale(0.98);
}

/* ARROW ANIMATION */
.arrow {
  font-size: 12px;
  transition: transform 0.2s ease;
}

.legend-item:hover .arrow {
  transform: translateX(4px);
}

.legend-item .dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  margin-right: 10px;
}

/* wrap text nicely */
.legend-item div {
  flex: 1;
  margin-left: 8px;
}

.legend-item.success .dot { background: #116AF8; }
.legend-item.failed .dot  { background: #ef4444; }
.legend-item.partial .dot { background: #f59e0b; }

.legend-item p {
  margin: 0;
  font-weight: 500;
}

.legend-item small {
  color: #64748b;
}

/* VALUE + ARROW */
.value {
  display: flex;
  align-items: center;
  gap: 6px;
  font-weight: 600;
}

sp_widget.script:
(function() {

	data.side = $sp.getWidget('tracenow_sidebar');

	var totalMigrations = 0;
	var successRuns = 0;
	var failedRuns = 0;
	var partialRuns = 0;
	var totalRecords = 0;

	var totalAvgMigrationDuration = 0; // Tracks logs that actually have durations

	var migrationGR = new GlideRecordSecure('x_sysus_tracenow_migration_details');
	migrationGR.addQuery('sys_created_by', gs.getUserName());
	migrationGR.query();

	while (migrationGR.next()) {
		var migrationDurationSeconds = 0;
		totalMigrations++;

		var migrationSysId = migrationGR.getUniqueValue();
		var successCount = 0;
		var failedCount = 0;
		var recordCount = 0;

		var logGR = new GlideRecordSecure('x_sysus_tracenow_tracenow_migration_record_log');
		logGR.addQuery('migration', migrationSysId);
		logGR.query();

		while (logGR.next()) {
			recordCount++;
			totalRecords++;

			// 1. Process Statuses
			var status = (logGR.getValue('status') || '').toLowerCase();
			if (status == 'success') {
				successCount++;
			} else if (status == 'failed') {
				failedCount++;
			}

			// 2. Process Durations INSIDE the record loop
			var durationStr = logGR.getValue('duration');
			if (durationStr) {
				// Regex uses (\d+) to capture numeric values cleanly
				var minMatch = durationStr.match(/(\d+)\s*min/);
				var secMatch = durationStr.match(/(\d+)\s*sec/);

				var minutes = minMatch ? parseInt(minMatch[1], 10) : 0;
				var seconds = secMatch ? parseInt(secMatch[1], 10) : 0;

				migrationDurationSeconds += (minutes * 60) + seconds;
			}
		}

		var avgMigrationDuration = 0;

		if (recordCount > 0) {
			avgMigrationDuration =
				migrationDurationSeconds / recordCount;
		}

		totalAvgMigrationDuration += avgMigrationDuration;

		// Calculate Migration Success Statuses
		var successRate = 0;
		if (recordCount > 0) {
			successRate = Math.round((successCount / recordCount) * 100);
		}

		if (successRate == 100) {
			successRuns++;
		} else if (successRate == 0) {
			failedRuns++;
		} else {
			partialRuns++;
		}
	}

	// Calculate Average Duration based on processed records
	var avgSeconds =
			totalMigrations > 0
	? Math.floor(
		totalAvgMigrationDuration /
		totalMigrations
	)
	: 0;
	var avgMin = Math.floor(avgSeconds / 60);
	var avgSec = avgSeconds % 60;

	// Output clean text string for HTML block
	data.avgDuration = avgMin + " min " + avgSec + " sec";

	// Standard metadata mapping
	data.totalCount = totalMigrations;
	data.totalRecords = totalRecords;
	data.successCount = successRuns;
	data.failedCount = failedRuns;
	data.partialCount = partialRuns;

	if (totalMigrations > 0) {
		data.successRate = ((successRuns / totalMigrations) * 100).toFixed(1);
		data.failureRate = ((failedRuns / totalMigrations) * 100).toFixed(1);
		data.partialRate = ((partialRuns / totalMigrations) * 100).toFixed(1);
	} else {
		data.successRate = 0;
		data.failureRate = 0;
		data.partialRate = 0;
	}

})();
